// src/shared/postJson.ts
function createPostJson({
  authHeaders,
  fetchCredentials
}) {
  return async function postJson(path, body) {
    return fetch(path, {
      method: "POST",
      headers: { "content-type": "application/json", ...authHeaders() },
      credentials: fetchCredentials,
      body: JSON.stringify(body)
    });
  };
}

// src/shared/memory.ts
function createMemoryAddTool({
  postJson,
  memoryAddPath
}) {
  return async (params) => {
    const fact = typeof params.fact === "string" ? params.fact : "";
    if (!fact.trim()) return "Memory save failed: empty fact.";
    try {
      const res = await postJson(memoryAddPath, { fact });
      if (!res.ok) return "Failed to save memory.";
      return "Memory saved.";
    } catch {
      return "Memory save failed.";
    }
  };
}
function createMemoryContextInjector({
  postJson,
  memoryRetrievePath,
  conversationRef,
  enabled,
  lastInjectedRef
}) {
  return async function inject(userText) {
    if (!enabled) return;
    try {
      const res = await postJson(memoryRetrievePath, { query: userText, limit: 4 });
      if (!res.ok) return;
      const data = await res.json();
      const results = data.results ?? [];
      if (!results.length) return;
      const lines = results.map((r) => `- ${r.chunk.trim().replace(/\s+/g, " ").slice(0, 200)}`).join("\n");
      if (lines === lastInjectedRef.current) return;
      lastInjectedRef.current = lines;
      const payload = `Relevant memory about this user:
${lines}`;
      conversationRef.current?.sendContextualUpdate(payload);
    } catch {
    }
  };
}

// src/shared/transcript.ts
function createTranscriptDisconnectHandler({
  isRestartingRef,
  weStartedSessionRef,
  transcriptRef,
  onTranscript,
  transcriptIngestPath,
  postJson
}) {
  return function handleTranscriptOnDisconnect() {
    if (isRestartingRef.current) {
      return;
    }
    if (!weStartedSessionRef.current) {
      transcriptRef.current = [];
      return;
    }
    weStartedSessionRef.current = false;
    const transcript = transcriptRef.current.join("\n");
    transcriptRef.current = [];
    if (onTranscript) {
      void onTranscript(transcript);
      return;
    }
    const trimmed = transcript.trim();
    if (trimmed.length < 20) return;
    void postJson(transcriptIngestPath, { transcript: trimmed }).catch(() => {
    });
  };
}
function appendTranscriptLine(msg, { transcriptRef, weStartedSessionRef }) {
  if (!msg?.message || !msg?.source) return;
  if (!weStartedSessionRef.current) return;
  const speaker = msg.source === "user" ? "User" : "Agent";
  const cleaned = msg.source === "user" ? msg.message : stripAudioTags(msg.message);
  if (!cleaned) return;
  transcriptRef.current.push(`${speaker}: ${cleaned}`);
}

// src/shared/sessionPayload.ts
function sanitizeDynamicVariables(raw) {
  if (raw == null) return {};
  const out = {};
  for (const [k, v] of Object.entries(raw)) {
    if (v == null) continue;
    out[k] = typeof v === "string" ? v : String(v);
  }
  return out;
}
function buildSessionPayload(opts) {
  const dynamicVariables = {
    ...sanitizeDynamicVariables(opts.dynamicVariables),
    character_name: opts.characterName,
    user_context: opts.userContext
  };
  if (typeof opts.conversationId === "string" && opts.conversationId.length > 0) {
    dynamicVariables.conversation_id = opts.conversationId;
  }
  const payload = {
    signedUrl: opts.signedUrl,
    dynamicVariables
  };
  const agentOverrides = {};
  if (opts.suppressFirstMessage) {
    agentOverrides.firstMessage = "";
  }
  if (typeof opts.agentPromptOverride === "string" && opts.agentPromptOverride.length > 0) {
    agentOverrides.prompt = { prompt: opts.agentPromptOverride };
  }
  if (Object.keys(agentOverrides).length > 0) {
    payload.overrides = { agent: agentOverrides };
  }
  return payload;
}
async function fetchSignedUrl({
  path,
  fetchCredentials,
  authHeaders
}) {
  const res = await fetch(path, {
    credentials: fetchCredentials,
    headers: authHeaders()
  });
  if (!res.ok) throw new Error(`Signed URL request failed: ${res.status}`);
  return await res.json();
}
function withProjectQuery(signedUrlPath, params) {
  const tail = [];
  if (typeof params.projectId === "string" && params.projectId.length > 0) {
    tail.push(`projectId=${encodeURIComponent(params.projectId)}`);
  }
  if (typeof params.agentName === "string" && params.agentName.length > 0) {
    tail.push(`agentName=${encodeURIComponent(params.agentName)}`);
  }
  if (tail.length === 0) return signedUrlPath;
  const sep = signedUrlPath.includes("?") ? "&" : "?";
  return `${signedUrlPath}${sep}${tail.join("&")}`;
}

// src/shared/chatUrl.ts
